+
+const prisma = new PrismaClient();
+
+async function createRun({
+  id,
+  friendlyId,
+  environmentId,
+  projectId,
+  taskIdentifier,
+  status = "PENDING",
+  parentTaskRunId,
+  rootTaskRunId,
+  depth = 0,
+}: {
+  id: string;
+  friendlyId: string;
+  environmentId: string;
+  projectId: string;
